mapper.sql:
WHERE so.staff_id = #{staffId}

    AND so.customer_id = #{customerId}


    AND c.customer_name LIKE CONCAT('%', #{customerName}, '%')


    AND c.phone = #{phone}


    AND so.order_status = #{orderStatus}


    AND so.vehicle_vin = #{vehicleVin}


    AND so.created_at >= #{createdAtStart}


    AND so.created_at <= #{createdAtEnd}
